export default function migration(): Rule {
  return chain([
    updateDependencies([
      {
        packageName: '@typescript-eslint/eslint-plugin',
        version: `^${updatedTypeScriptESLintVersion}`,
      },
      {
        packageName: '@typescript-eslint/utils',
        version: `^${updatedTypeScriptESLintVersion}`,
      },
      {
        packageName: '@typescript-eslint/parser',
        version: `^${updatedTypeScriptESLintVersion}`,
      },
      {
        packageName: 'eslint',
        version: `^${updatedESLintVersion}`,
      },
    ]),
    updateJsonInTree('angular.json', (json) => {
      return updateSchematicDefaults(
        json,
        '@angular-eslint/schematics:application',
        {
          setParserOptionsProject: true,
        },
      );
    }),
    updateJsonInTree('angular.json', (json) => {
      return updateSchematicDefaults(
        json,
        '@angular-eslint/schematics:library',
        {
          setParserOptionsProject: true,
        },
      );
    }),
  ]);
}

import ts from 'typescript';
import * as Lint from 'tslint';

export class Rule extends Lint.Rules.AbstractRule {
  apply(sourceFile: ts.SourceFile): Lint.RuleFailure[] {
    return this.applyWithWalker(new Walker(sourceFile, this.getOptions()));
  }
}

class Walker extends Lint.RuleWalker {
  override visitClassDeclaration(node: ts.ClassDeclaration) {
    if (!node.modifiers || !this.getOptions().length) {
      return;
    }

    // Do not check the class if its abstract.
    if (!!node.modifiers.find(modifier => modifier.kind === ts.SyntaxKind.AbstractKeyword)) {
      return;
    }

    node.members.forEach(member => {
      if (
        !ts.isPropertyDeclaration(member) &&
        !ts.isMethodDeclaration(member) &&
        !ts.isGetAccessorDeclaration(member) &&
        !ts.isSetAccessorDeclaration(member)
      ) {
        return;
      }

      const decorators = ts.getDecorators(member);

      decorators?.forEach(decorator => {
        const decoratorText: string = decorator.getChildAt(1).getText();
        const matchedDecorator: string = this.getOptions().find((item: string) =>
          decoratorText.startsWith(item),
        );
        if (!!matchedDecorator) {
          this.addFailureFromStartToEnd(
            decorator.getChildAt(1).pos - 1,
            decorator.end,
            `The @${matchedDecorator} decorator may only be used in abstract classes. In ` +
              `concrete classes use \`host\` in the component definition instead.`,
          );
        }
      });
    });

    super.visitClassDeclaration(node);
  }
}

import {
  Rule,
  SchematicContext,
  SchematicsException,
  Tree,
  apply,
  applyTemplates,
  branchAndMerge,
  chain,
  filter,
  mergeWith,
  move,
  noop,
  template,
  url,
} from '@angular-devkit/schematics';
import {
  getProjectPath,
  findModuleFromOptions,
  stringUtils,
  addReducerToState,
  addReducerImportToNgModule,
  parseName,
  getProject,
  getPrefix,
} from '../../schematics-core';
import { Schema as ReducerOptions } from './schema';

export default function (options: ReducerOptions): Rule {
  return (host: Tree, context: SchematicContext) => {
    const projectConfig = getProject(host, options);
    options.path = getProjectPath(host, options);
    options.prefix = getPrefix(options);

    const parsedPath = parseName(options.path, options.name);
    options.name = parsedPath.name;
    options.path = parsedPath.path;

    if (options.module) {
      options.module = findModuleFromOptions(host, options);
    }

    const templateOptions = {
      ...stringUtils,
      'if-flat': (s: string) =>
        stringUtils.group(
          options.flat ? '' : s,
          options.group ? 'reducers' : ''
        ),
      ...(options as object),
    };

    const templateSource = apply(url('./files'), [
      options.skipTests
        ? filter((path) => !path.endsWith('.spec.ts.template'))
        : noop(),
      applyTemplates(templateOptions),
      move(parsedPath.path),
    ]);

    return chain([
      branchAndMerge(chain([addReducerToState(options)])),
      branchAndMerge(
        chain([addReducerImportToNgModule(options), mergeWith(templateSource)])
      ),
    ])(host, context);
  };
}

import {
  Rule,
  SchematicContext,
  Tree,
  apply,
  applyTemplates,
  branchAndMerge,
  chain,
  filter,
  mergeWith,
  move,
  noop,
  url,
} from '@angular-devkit/schematics';
import { getProjectPath, parseName, stringUtils } from '../../schematics-core';
import { Schema as SelectorOptions } from './schema';

export default function (options: SelectorOptions): Rule {
  return (host: Tree, context: SchematicContext) => {
    options.path = getProjectPath(host, options);

    const parsedPath = parseName(options.path, options.name || '');
    options.name = parsedPath.name;
    options.path = parsedPath.path;

    const templateSource = apply(url('./files'), [
      options.skipTests
        ? filter((path) => !path.endsWith('.spec.ts.template'))
        : noop(),
      applyTemplates({
        ...stringUtils,
        'if-flat': (s: string) =>
          stringUtils.group(
            options.flat ? '' : s,
            options.group ? 'selectors' : ''
          ),
        reducerPath: `${relativePath(options)}${stringUtils.dasherize(
          options.name
        )}.reducer`,
        ...(options as object),
      } as any),
      move(parsedPath.path),
    ]);

    return chain([branchAndMerge(chain([mergeWith(templateSource)]))])(
      host,
      context
    );
  };
}

function relativePath(options: SelectorOptions) {
  if (options.feature) {
    return stringUtils.featurePath(
      options.group,
      options.flat,
      'reducers',
      stringUtils.dasherize(options.name)
    );
  }

  return '';
}

import type { Rule, SchematicContext, Tree } from '@angular-devkit/schematics';
import { chain } from '@angular-devkit/schematics';
import { NodePackageInstallTask } from '@angular-devkit/schematics/tasks';
import { updateJsonInTree } from '../../utils';

export function updateDependencies(
  depsToUpdate: { packageName: string; version: string }[],
): Rule {
  return chain([
    updateJsonInTree('package.json', (json) => {
      for (const { packageName, version } of depsToUpdate) {
        updateIfExists(json, packageName, version);
      }
      return json;
    }),
    (_: Tree, context: SchematicContext) => {
      context.addTask(new NodePackageInstallTask());
    },
  ]);
}

function updateIfExists(
  packageJson:
    | {
        dependencies?: Record<string, string>;
        devDependencies?: Record<string, string>;
      }
    | undefined,
  depName: string,
  updatedVersion: string,
) {
  if (!packageJson) {
    return;
  }
  if (packageJson.dependencies && packageJson.dependencies[depName]) {
    packageJson.dependencies[depName] = updatedVersion;
  }
  if (packageJson.devDependencies && packageJson.devDependencies[depName]) {
    packageJson.devDependencies[depName] = updatedVersion;
  }
}

