import { Component, computed, input } from '@angular/core';
import { ApiMember } from '@ngrx-io/shared';
import { SymbolExcerptComponent } from './symbol-excerpt.component';

@Component({
  selector: 'ngrx-symbol-type-params',
  standalone: true,
  imports: [SymbolExcerptComponent],
  template: `
    @for (param of params(); track $index) {
      <div class="param">
        <code class="paramSymbol">{{ '@type' }}</code>
        <code class="name">{{ param.name }}</code>
        <ngrx-symbol-excerpt [excerptTokens]="param.excerptTokens" />
      </div>
    }
  `,
  styles: [
    `
      :host {
        display: block;
        border-top: 1px solid var(--ngrx-border-color);
      }

      .param {
        display: grid;
        padding: 8px;
        align-items: center;
        grid-template-columns: 96px 112px 1fr;
        gap: 16px;
      }

      .param:last-child {
        border-bottom: 1px solid var(--ngrx-border-color);
      }

      .paramSymbol {
        font-weight: 700;
        color: var(--ngrx-link);
      }

      code {
        font-family: 'Oxanium', sans-serif;
        padding: 0.25em 0.5em;
        border-radius: 4px;
        font-size: 15px;
      }
    `,
  ],
})
export class SymbolTypeParamsComponent {
  symbol = input.required<ApiMember>();
  params = computed(() => {
    const parameters = this.symbol().typeParameters || [];
    return parameters.map((param) => {
      return {
        name: param.typeParameterName,
        excerptTokens: [
          ...this.symbol().excerptTokens.slice(
            param.constraintTokenRange.startIndex,
            param.constraintTokenRange.endIndex
          ),
        ],
      };
    });
  });
}

import { Injectable, Injector, NgZone, OnDestroy } from '@angular/core';
import { VERSION } from '@angular/fire';
import { Auth, authState } from '@angular/fire/auth';
import { registerVersion } from 'firebase/app';
import { Subscription } from 'rxjs';
import { Analytics } from './analytics';
import { isSupported, setUserId } from './firebase';

@Injectable()
export class UserTrackingService implements OnDestroy {

  public readonly initialized: Promise<void>;
  private disposables: Subscription[] = [];

  constructor(
    auth: Auth,
    zone: NgZone,
    injector: Injector,
  ) {
    registerVersion('angularfire', VERSION.full, 'user-tracking');
    let resolveInitialized: () => void;
    this.initialized = zone.runOutsideAngular(() => new Promise(resolve => { resolveInitialized = resolve; }));
    // The APP_INITIALIZER that is making isSupported() sync for the sake of convenient DI
    // may not be done when services are initialized. Guard the functionality by first ensuring
    // that the (global) promise has resolved, then get Analytics from the injector.
    isSupported().then(() => {
      const analytics = injector.get(Analytics);
      if (analytics) {
        this.disposables = [
          // TODO add credential tracking back in
          authState(auth).subscribe(user => {
            setUserId(analytics, user?.uid);
            resolveInitialized();
          }),
        ];
      } else {
        resolveInitialized();
      }
    });
  }

  ngOnDestroy() {
    this.disposables.forEach(it => it.unsubscribe());
  }
}

import { Component, ChangeDetectionStrategy, Type } from '@angular/core';
import { FieldTypeConfig, FormlyFieldConfig } from '@ngx-formly/core';
import { FieldType, FormlyFieldProps } from '@ngx-formly/material/form-field';

interface InputProps extends FormlyFieldProps {}

export interface FormlyInputFieldConfig extends FormlyFieldConfig<InputProps> {
  type: 'input' | Type<FormlyFieldInput>;
}

